/* Chart.js Simplified Version - Local Build */
(function() {
    window.Chart = function(ctx, config) {
        this.ctx = ctx;
        this.config = config;
        this.draw();
    };

    Chart.prototype.draw = function() {
        const type = this.config.type;
        const data = this.config.data;
        const canvas = this.ctx.canvas;
        const w = canvas.width;
        const h = canvas.height;
        const ctx = this.ctx;

        ctx.clearRect(0, 0, w, h);

        if (type === 'doughnut' || type === 'pie') {
            this.drawDoughnut(ctx, w, h, data);
        } else if (type === 'bar') {
            this.drawBar(ctx, w, h, data);
        }
    };

    Chart.prototype.drawDoughnut = function(ctx, w, h, data) {
        const cx = w / 2;
        const cy = h / 2;
        const radius = Math.min(w, h) / 2 - 40;
        const colors = data.datasets[0].backgroundColor;
        const values = data.datasets[0].data;
        const total = values.reduce((a, b) => a + b, 0);
        
        let angle = -Math.PI / 2;
        
        values.forEach((value, i) => {
            const sliceAngle = (value / total) * Math.PI * 2;
            
            // Draw slice
            ctx.beginPath();
            ctx.arc(cx, cy, radius, angle, angle + sliceAngle);
            ctx.arc(cx, cy, radius * 0.6, angle + sliceAngle, angle, true);
            ctx.fillStyle = colors[i];
            ctx.fill();
            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 2;
            ctx.stroke();
            
            // Draw label
            const labelAngle = angle + sliceAngle / 2;
            const labelX = cx + Math.cos(labelAngle) * (radius * 0.75);
            const labelY = cy + Math.sin(labelAngle) * (radius * 0.75);
            ctx.fillStyle = '#fff';
            ctx.font = 'bold 12px Arial';
            ctx.textAlign = 'center';
            ctx.fillText(value, labelX, labelY);
            
            angle += sliceAngle;
        });
        
        // Draw legend
        let legendY = h - 30;
        data.labels.forEach((label, i) => {
            ctx.fillStyle = colors[i];
            ctx.fillRect(20, legendY - 10, 15, 15);
            ctx.fillStyle = '#333';
            ctx.font = '12px Arial';
            ctx.textAlign = 'left';
            ctx.fillText(label + ' (' + values[i] + ')', 40, legendY);
            legendY += 20;
        });
    };

    Chart.prototype.drawBar = function(ctx, w, h, data) {
        const padding = 60;
        const graphWidth = w - padding * 2;
        const graphHeight = h - padding * 2;
        const labels = data.labels;
        const datasets = data.datasets;
        const maxValue = Math.max(...datasets.flatMap(d => d.data));
        
        ctx.fillStyle = '#f5f5f5';
        ctx.fillRect(padding, padding, graphWidth, graphHeight);
        
        // Draw grid
        ctx.strokeStyle = '#ddd';
        ctx.lineWidth = 1;
        for (let i = 0; i <= 5; i++) {
            const y = padding + (graphHeight / 5) * i;
            ctx.beginPath();
            ctx.moveTo(padding, y);
            ctx.lineTo(padding + graphWidth, y);
            ctx.stroke();
        }
        
        // Draw axes
        ctx.strokeStyle = '#333';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(padding, padding);
        ctx.lineTo(padding, padding + graphHeight);
        ctx.lineTo(padding + graphWidth, padding + graphHeight);
        ctx.stroke();
        
        // Draw bars
        const barWidth = graphWidth / (labels.length * (datasets.length + 1));
        let xPos = padding + barWidth;
        
        labels.forEach((label, i) => {
            datasets.forEach((dataset, j) => {
                const value = dataset.data[i];
                const barHeight = (value / maxValue) * graphHeight;
                const y = padding + graphHeight - barHeight;
                
                ctx.fillStyle = dataset.backgroundColor;
                ctx.fillRect(xPos, y, barWidth * 0.8, barHeight);
                xPos += barWidth;
            });
            xPos += barWidth;
        });
        
        // Draw labels
        ctx.fillStyle = '#333';
        ctx.font = '12px Arial';
        ctx.textAlign = 'center';
        xPos = padding + barWidth * (1.5 + datasets.length / 2);
        labels.forEach((label, i) => {
            ctx.fillText(label, xPos, padding + graphHeight + 20);
            xPos += barWidth * (datasets.length + 1);
        });
        
        // Draw legend
        let legendX = padding;
        datasets.forEach((dataset, i) => {
            ctx.fillStyle = dataset.backgroundColor;
            ctx.fillRect(legendX, 10, 15, 15);
            ctx.fillStyle = '#333';
            ctx.font = '12px Arial';
            ctx.textAlign = 'left';
            ctx.fillText(dataset.label, legendX + 20, 22);
            legendX += 150;
        });
    };
})();